const response = await client.messages.create({
  model: "claude-4-sonnet-20251027",
  messages: [{ role: "user", content: "What's AAPL's stock price?" }],
  tools: [getStockPriceTool]
});

// Step 2: Extract tool_use blocks
if (response.stop_reason === "tool_use") {
  const toolUseBlocks = response.content.filter(c => c.type === "tool_use");

  // Step 3: Execute each tool
  const results = await Promise.all(
    toolUseBlocks.map(async (block) => {
      const { name, input, id } = block;

      // Validate input before execution
      if (typeof input.symbol !== "string") {
        throw new Error("symbol must be a string");
      }

      // Execute the tool
      const result = executeTool(name, input);

      return { toolUseId: id, result: result };
    })
  );

  // Step 4: Send tool_result back
  const toolResultBlocks = results.map(r => ({
    type: "tool_result",
    tool_use_id: r.toolUseId,
    content: r.result.toString()
  }));

  const response2 = await client.messages.create({
    model: "claude-4-sonnet-20251027",
    messages: [
      ...response.messages,
      { role: "user", content: toolResultBlocks }
    ],
    tools: [getStockPriceTool]
  });

  // Step 5: Claude gives final answer
  console.log(response2.content[0].text);
  // "AAPL is currently trading at $175.43"
}

